const email = String($json['מייל'] || '').trim();
const sentAt = String($json['אישור מייל נשלח'] || '').trim();
const orderNumber = String($json['מספר הזמנה'] || '').trim();
const pickup = String($json['מוקד איסוף מלא'] || '').trim();
const model = String($json['מספר דגם'] || '').trim();
const books = String($json['כמות חבילות ספרים'] || '0').trim();
const notebooks = String($json['כמות חבילות מחברות'] || '0').trim();
const englishBooks = String($json['כמות חבילות ספרי אנגלית'] || '0').trim();
const englishNotebooks = String($json['כמות חבילות מחברות אנגלית'] || '0').trim();
const enteredPhone = String($json['טלפון שהוקש'] || '').trim();
const idNumber = String($json['תעודת זהות'] || '').trim();
const status = String($json['סטטוס'] || 'התקבלה').trim();
const productsSummary = String($json['מוצרים שנבחרו'] || '').trim();
const orderSummary = String($json['סיכום הזמנה מלא'] || '').trim();
const wantsHebrew = String($json['שם אישי בעברית'] || '').trim();
const hebrewName = String($json['הקלטת שם עברי'] || '').trim();
const hebrewFont = String($json['גופן עברי'] || '').trim();
const hasEnglishLetters = String($json['יש אנגלית בדוגמה'] || '').trim();
const englishLetters = String($json['הקלטת אותיות באנגלית'] || '').trim();
const wantsEnglishName = String($json['שם אישי לאנגלית'] || '').trim();
const englishNameLanguage = String($json['שפת השם באנגלית'] || '').trim();
const englishName = String($json['הקלטת שם אנגלי'] || '').trim();
const englishFont = String($json['גופן אנגלי'] || '').trim();

const personalization = [];
if (wantsHebrew === 'כן') {
  personalization.push(`שם אישי בעברית: ${hebrewName || 'נבחר'}${hebrewFont ? `, גופן ${hebrewFont}` : ''}`);
}
if (hasEnglishLetters === 'כן') {
  personalization.push(`אותיות באנגלית בדוגמה: ${englishLetters || 'כן'}`);
}
if (wantsEnglishName === 'כן') {
  personalization.push(`שם אישי עבור ספרי אנגלית: ${englishName || 'נבחר שם אישי'}, שפה ${englishNameLanguage || 'לא צוין'}${englishFont ? `, גופן ${englishFont}` : ''}`);
}
if (productsSummary) {
  personalization.push(`מוצרים שנבחרו: ${productsSummary}`);
}

const html = `
<div dir="rtl" style="margin:0;padding:32px 16px;background:linear-gradient(180deg,#fff8f1 0%,#fffdfb 100%);font-family:Arial,'Noto Sans Hebrew',sans-serif;color:#3b2c25">
  <div style="max-width:720px;margin:0 auto;background:#ffffff;border:1px solid #f0d9cb;border-radius:30px;overflow:hidden;box-shadow:0 22px 56px rgba(170,118,105,0.12)">
    <div style="padding:32px;background:radial-gradient(circle at top right,rgba(212,106,140,0.16),transparent 32%),radial-gradient(circle at bottom left,rgba(239,178,113,0.18),transparent 28%),linear-gradient(135deg,#fff8f4 0%,#fff4ea 100%)">
      <div style="font-size:15px;font-weight:700;color:#b55a7b;margin-bottom:10px">קראנץ</div>
      <div style="font-size:28px;font-weight:800;line-height:1.2;margin-bottom:10px">ההזמנה שלך התקבלה בהצלחה</div>
      <div style="font-size:16px;line-height:1.8;color:#7b6258">ריכזנו עבורך כאן את פרטי ההזמנה, לפי הבחירות והכמויות שנשמרו עבורך.</div>
    </div>
    <div style="padding:28px 32px 18px">
      <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px">
        ${[
          ['מספר הזמנה', orderNumber],
          ['סטטוס', status],
          ['מוקד איסוף', pickup],
          ['טלפון', enteredPhone],
          ['תעודת זהות', idNumber],
          ['דגם', model]
        ].filter(([, value]) => value).map(([label, value]) => `
          <div style="padding:14px 16px;border-radius:18px;background:#fffaf6;border:1px solid #f3dfd4">
            <div style="font-size:13px;color:#9b7b6f;margin-bottom:6px">${label}</div>
            <div style="font-size:17px;font-weight:700;color:#44312a">${value}</div>
          </div>
        `).join('')}
      </div>
    </div>
    <div style="padding:0 32px 12px">
      <div style="font-size:21px;font-weight:800;margin-bottom:14px">פירוט הכמויות</div>
      <div style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px">
        ${[
          ['חבילות ספרים', books],
          ['חבילות מחברות', notebooks],
          ['ספרי אנגלית', englishBooks],
          ['מחברות אנגלית', englishNotebooks]
        ].map(([label, value]) => `
          <div style="padding:16px 12px;border-radius:20px;background:linear-gradient(180deg,#fff7f0,#fffdfb);border:1px solid #f3dfd4;text-align:center">
            <div style="font-size:14px;color:#8f7066;margin-bottom:8px">${label}</div>
            <div style="font-size:24px;font-weight:800;color:#c0587d">${value}</div>
          </div>
        `).join('')}
      </div>
    </div>
    <div style="padding:12px 32px 0">
      <div style="border-radius:24px;background:#fffaf6;border:1px solid #f3dfd4;padding:20px 22px">
        <div style="font-size:21px;font-weight:800;margin-bottom:12px">התאמות אישיות שנבחרו</div>
        ${personalization.length ? `<ul style="margin:0;padding:0 18px 0 0;color:#5a473e;line-height:1.95">${personalization.map((item) => `<li>${item}</li>`).join('')}</ul>` : `<div style="color:#7f665d;line-height:1.8">לא נבחרו התאמות אישיות מיוחדות להזמנה זו.</div>`}
      </div>
    </div>
    <div style="padding:20px 32px 32px">
      <div style="border-radius:24px;background:linear-gradient(135deg,#fff2ec,#fff9f4);border:1px solid #f0ddd1;padding:20px 22px">
        <div style="font-size:18px;font-weight:800;margin-bottom:8px">סיכום הזמנה מלא</div>
        <div style="color:#6f5a51;line-height:1.9">${orderSummary || productsSummary || ''}</div>
      </div>
      <div style="margin-top:18px;font-size:14px;color:#8b7166;line-height:1.8">תודה שבחרת בקראנץ. נשמח לשרת אותך גם בהזמנות הבאות.</div>
    </div>
  </div>
</div>`;

return {
  ...$json,
  email,
  orderNumber,
  shouldSend: Boolean(email) && !sentAt,
  html,
  sentAtValue: new Date().toISOString(),
  sentStatusValue: 'נשלח',
  rowNumber: $json.rowNumber || $json._rowNumber || ''
};
